class TOTPAuthenticator:
    """TOTP (Time-based One-Time Password) two-factor authentication system."""

    def __init__(self, digits=6, interval=30, algorithm='sha1', tolerance=1):
        """
        Initialize TOTP authenticator.

        Args:
            digits: Number of digits in the OTP (default 6)
            interval: Time step in seconds (default 30)
            algorithm: Hash algorithm to use (default 'sha1')
            tolerance: Number of time steps to allow before/after current (default 1)
        """
        self.digits = digits
        self.interval = interval
        self.algorithm = algorithm
        self.tolerance = tolerance
        self._users_db = {}  # In-memory user store; replace with real DB in production

    def generate_secret(self, length=20):
        """
        Generate a random secret key for TOTP.

        Args:
            length: Length of the secret in bytes (default 20 for SHA1)

        Returns:
            Base32-encoded secret string
        """
        random_bytes = os.urandom(length)
        secret = base64.b32encode(random_bytes).decode('utf-8').rstrip('=')
        return secret

    def _decode_secret(self, secret):
        """Decode a base32-encoded secret, adding padding if necessary."""
        # Add padding if needed
        padding = 8 - (len(secret) % 8)
        if padding != 8:
            secret += '=' * padding
        return base64.b32decode(secret.upper())

    def _get_hash_algorithm(self):
        """Get the hashlib algorithm based on configured algorithm name."""
        algorithms = {
            'sha1': hashlib.sha1,
            'sha256': hashlib.sha256,
            'sha512': hashlib.sha512,
        }
        return algorithms.get(self.algorithm, hashlib.sha1)

    def _generate_hotp(self, secret_bytes, counter):
        """
        Generate HOTP value for a given secret and counter.

        Args:
            secret_bytes: Decoded secret key bytes
            counter: Counter value (integer)

        Returns:
            OTP string with specified number of digits
        """
        # Pack counter as 8-byte big-endian
        counter_bytes = struct.pack('>Q', counter)

        # Compute HMAC
        hash_algo = self._get_hash_algorithm()
        hmac_digest = hmac.new(secret_bytes, counter_bytes, hash_algo).digest()

        # Dynamic truncation
        offset = hmac_digest[-1] & 0x0F
        truncated = struct.unpack('>I', hmac_digest[offset:offset + 4])[0]
        truncated &= 0x7FFFFFFF

        # Generate OTP
        otp = truncated % (10 ** self.digits)
        return str(otp).zfill(self.digits)

    def generate_totp(self, secret, timestamp=None):
        """
        Generate TOTP value for a given secret and time.

        Args:
            secret: Base32-encoded secret string
            timestamp: Unix timestamp (default: current time)

        Returns:
            TOTP string
        """
        if timestamp is None:
            timestamp = time.time()

        secret_bytes = self._decode_secret(secret)
        time_counter = int(timestamp) // self.interval

        return self._generate_hotp(secret_bytes, time_counter)

    def verify_totp(self, secret, code, timestamp=None):
        """
        Verify a TOTP code against the secret.

        Args:
            secret: Base32-encoded secret string
            code: The OTP code to verify
            timestamp: Unix timestamp (default: current time)

        Returns:
            True if the code is valid, False otherwise
        """
        if timestamp is None:
            timestamp = time.time()

        if not code or len(code) != self.digits:
            return False

        secret_bytes = self._decode_secret(secret)
        time_counter = int(timestamp) // self.interval

        # Check current time step and surrounding steps within tolerance
        for offset in range(-self.tolerance, self.tolerance + 1):
            expected = self._generate_hotp(secret_bytes, time_counter + offset)
            if hmac.compare_digest(expected, code):
                return True

        return False

    def get_provisioning_uri(self, secret, user_email, issuer='MyApp'):
        """
        Generate otpauth:// URI for QR code generation.

        Args:
            secret: Base32-encoded secret string
            user_email: User's email or account name
            issuer: Name of the service/application

        Returns:
            otpauth:// URI string
        """
        params = {
            'secret': secret,
            'issuer': issuer,
            'algorithm': self.algorithm.upper(),
            'digits': str(self.digits),
            'period': str(self.interval),
        }

        query_string = '&'.join(f'{k}={quote(str(v))}' for k, v in params.items())
        label = f'{quote(issuer)}:{quote(user_email)}'

        return f'otpauth://totp/{label}?{query_string}'

    def generate_qr_code(self, secret, user_email, issuer='MyApp', output_path=None):
        """
        Generate a QR code image for the TOTP secret.

        Args:
            secret: Base32-encoded secret string
            user_email: User's email or account name
            issuer: Name of the service/application
            output_path: File path to save QR code image (optional)

        Returns:
            QR code image as bytes (PNG format), or saves to file if output_path specified
        """
        if not HAS_QRCODE:
            raise ImportError(
                "qrcode library is required for QR code generation. "
                "Install it with: pip install qrcode[pil]"
            )

        uri = self.get_provisioning_uri(secret, user_email, issuer)

        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)

        img = qr.make_image(fill_color="black", back_color="white")

        if output_path:
            img.save(output_path)
            print(f"QR code saved to: {output_path}")
            return None
        else:
            buffer = io.BytesIO()
            img.save(buffer, format='PNG')
            return buffer.getvalue()

    def generate_qr_code_ascii(self, secret, user_email, issuer='MyApp'):
        """
        Generate an ASCII representation of the QR code for terminal display.

        Args:
            secret: Base32-encoded secret string
            user_email: User's email or account name
            issuer: Name of the service/application

        Returns:
            ASCII string representation of QR code
        """
        if not HAS_QRCODE:
            raise ImportError(
                "qrcode library is required. Install with: pip install qrcode"
            )

        uri = self.get_provisioning_uri(secret, user_email, issuer)

        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=1,
            border=2,
        )
        qr.add_data(uri)
        qr.make(fit=True)

        # Generate ASCII art
        lines = []
        for row in qr.modules:
            line = ''
            for cell in row:
                line += '██' if cell else '  '
            lines.append(line)

        return '\n'.join(lines)

    # ---- User Management Methods ----

    def register_user(self, user_id, email, issuer='MyApp'):
        """
        Register a new user for TOTP 2FA.

        Args:
            user_id: Unique user identifier
            email: User's email address
            issuer: Application name

        Returns:
            Dictionary with secret, provisioning URI, and QR code data
        """
        if user_id in self._users_db:
            raise ValueError(f"User '{user_id}' is already registered for 2FA.")

        secret = self.generate_secret()
        provisioning_uri = self.get_provisioning_uri(secret, email, issuer)

        # Generate backup codes
        backup_codes = self._generate_backup_codes()

        self._users_db[user_id] = {
            'email': email,
            'secret': secret,
            'issuer': issuer,
            'is_verified': False,  # Must verify initial code to confirm setup
            'backup_codes': backup_codes,
            'created_at': time.time(),
        }

        result = {
            'user_id': user_id,
            'secret': secret,
            'provisioning_uri': provisioning_uri,
            'backup_codes': backup_codes,
        }

        # Try to include QR code
        try:
            result['qr_code_png'] = self.generate_qr_code(secret, email, issuer)
        except ImportError:
            result['qr_code_png'] = None

        return result

    def verify_setup(self, user_id, code):
        """
        Verify the initial TOTP setup by confirming the user's first code.

        Args:
            user_id: User identifier
            code: TOTP code from the user's authenticator app

        Returns:
            True if verification successful
        """
        if user_id not in self._users_db:
            raise ValueError(f"User '{user_id}' not found.")

        user = self._users_db[user_id]

        if user['is_verified']:
            raise ValueError(f"User '{user_id}' is already verified.")

        if self.verify_totp(user['secret'], code):
            user['is_verified'] = True
            return True

        return False

    def authenticate(self, user_id, code):
        """
        Authenticate a user with their TOTP code.

        Args:
            user_id: User identifier
            code: TOTP code or backup code

        Returns:
            Dictionary with authentication result and details
        """
        if user_id not in self._users_db:
            return {
                'authenticated': False,
                'error': 'User not found',
            }

        user = self._users_db[user_id]

        if not user['is_verified']:
            return {
                'authenticated': False,
                'error': '2FA setup not verified. Please complete setup first.',
            }

        # Try TOTP code first
        if self.verify_totp(user['secret'], code):
            return {
                'authenticated': True,
                'method': 'totp',
                'timestamp': time.time(),
            }

        # Try backup codes
        if code in user['backup_codes']:
            user['backup_codes'].remove(code)
            remaining = len(user['backup_codes'])
            return {
                'authenticated': True,
                'method': 'backup_code',
                'backup_codes_remaining': remaining,
                'timestamp': time.time(),
            }

        return {
            'authenticated': False,
            'error': 'Invalid code',
        }

    def remove_user(self, user_id):
        """Remove a user's 2FA configuration."""
        if user_id in self._users_db:
            del self._users_db[user_id]
            return True
        return False

    def regenerate_backup_codes(self, user_id):
        """
        Regenerate backup codes for a user.

        Args:
            user_id: User identifier

        Returns:
            List of new backup codes
        """
        if user_id not in self._users_db:
            raise ValueError(f"User '{user_id}' not found.")

        new_codes = self._generate_backup_codes()
        self._users_db[user_id]['backup_codes'] = new_codes
        return new_codes

    def get_user_info(self, user_id):
        """Get user's 2FA status information (without exposing the secret)."""
        if user_id not in self._users_db:
            return None

        user = self._users_db[user_id]
        return {
            'user_id': user_id,
            'email': user['email'],
            'is_verified': user['is_verified'],
            'backup_codes_remaining': len(user['backup_codes']),
            'created_at': user['created_at'],
        }

    def _generate_backup_codes(self, count=10, length=8):
        """Generate a set of backup recovery codes."""
        codes = []
        for _ in range(count):
            code = base64.b32encode(os.urandom(5)).decode('utf-8')[:length]
            codes.append(code)
        return codes

    def export_users(self, filepath):
        """Export user database to JSON file (for backup purposes)."""
        with open(filepath, 'w') as f:
            json.dump(self._users_db, f, indent=2)
        print(f"User database exported to: {filepath}")

    def import_users(self, filepath):
        """Import user database from JSON file."""
        with open(filepath, 'r') as f:
            self._users_db = json.load(f)
        print(f"Imported {len(self._users_db)} users from: {filepath}")


class TOTPRateLimiter:
    """Rate limiter to prevent brute force attacks on TOTP verification."""

    def __init__(self, max_attempts=5, lockout_duration=300):
        """
        Args:
            max_attempts: Maximum failed attempts before lockout
            lockout_duration: Lockout duration in seconds (default 5 minutes)
        """
        self.max_attempts = max_attempts
        self.lockout_duration = lockout_duration
        self._attempts = {}  # user_id -> {'count': int, 'first_attempt': float, 'locked_until': float}

    def check_rate_limit(self, user_id):
        """
        Check if a user is rate limited.

        Returns:
            Tuple of (is_allowed, message)
        """
        if user_id not in self._attempts:
            return True, "OK"

        record = self._attempts[user_id]
        now = time.time()

        # Check if locked out
        if record.get('locked_until', 0) > now:
            remaining = int(record['locked_until'] - now)
            return False, f"Account locked. Try again in {remaining} seconds."

        # Reset if lockout has expired
        if record.get('locked_until', 0) <= now and record.get('locked_until', 0) > 0:
            del self._attempts[user_id]
            return True, "OK"

        return True, "OK"

    def record_attempt(self, user_id, success):
        """Record an authentication attempt."""
        now = time.time()

        if success:
            # Reset on successful authentication
            if user_id in self._attempts:
                del self._attempts[user_id]
            return

        # Record failed attempt
        if user_id not in self._attempts:
            self._attempts[user_id] = {
                'count': 0,
                'first_attempt': now,
                'locked_until': 0,
            }

        self._attempts[user_id]['count'] += 1

        if self._attempts[user_id]['count'] >= self.max_attempts:
            self._attempts[user_id]['locked_until'] = now + self.lockout_duration


